4881	static bool sse_headers(int fd, bool enable_cors) {
4882	    buf h = {0};
4883	    buf_puts(&h,
4884	        "HTTP/1.1 200 OK\r\n"
4885	        "Content-Type: text/event-stream\r\n"
4886	        "Cache-Control: no-cache\r\n");
4887	    if (enable_cors) append_cors_headers(&h);
4888	    buf_puts(&h, "Connection: close\r\n\r\n");
4889	    bool ok = send_all(fd, h.ptr, h.len);
4890	    buf_free(&h);
4891	    return ok;
4892	}
