4894	static bool sse_error_event(int fd, const request *r, const char *msg) {
4895	    const char *message = msg && msg[0] ? msg : "internal server error";
4896	    buf b = {0};
4897	    if (r && r->api == API_ANTHROPIC) {
4898	        buf_puts(&b, "event: error\ndata: {\"type\":\"error\",\"error\":{\"type\":\"api_error\",\"message\":");
4899	        json_escape(&b, message);
4900	        buf_puts(&b, "}}\n\n");
4901	    } else {
4902	        buf_puts(&b, "event: error\ndata: {\"error\":{\"message\":");
4903	        json_escape(&b, message);
4904	        buf_puts(&b, ",\"type\":\"server_error\"}}\n\n");
4905	    }
4906	    bool ok = send_all(fd, b.ptr, b.len);
4907	    buf_free(&b);
4908	    return ok;
4909	}
