4911	static bool sse_chunk(int fd, const request *r, const char *id, const char *text, const char *finish) {
4912	    buf b = {0};
4913	    long now = (long)time(NULL);
4914	    if (r->kind == REQ_CHAT) {
4915	        buf_printf(&b, "data: {\"id\":\"%s\",\"object\":\"chat.completion.chunk\",\"created\":%ld,\"model\":", id, now);
4916	        json_escape(&b, r->model);
4917	        buf_puts(&b, ",\"choices\":[{\"index\":0,\"delta\":");
4918	        if (text) {
4919	            buf_puts(&b, "{\"content\":");
4920	            json_escape(&b, text);
4921	            buf_putc(&b, '}');
4922	        } else {
4923	            buf_puts(&b, finish ? "{}" : "{\"role\":\"assistant\"}");
4924	        }
4925	        buf_puts(&b, ",\"finish_reason\":");
4926	        if (finish) json_escape(&b, finish); else buf_puts(&b, "null");
4927	        buf_puts(&b, "}]}\n\n");
4928	    } else {
4929	        buf_printf(&b, "data: {\"id\":\"%s\",\"object\":\"text_completion\",\"created\":%ld,\"model\":", id, now);
4930	        json_escape(&b, r->model);
4931	        buf_puts(&b, ",\"choices\":[{\"text\":");
4932	        json_escape(&b, text ? text : "");
4933	        buf_puts(&b, ",\"index\":0,\"finish_reason\":");
4934	        if (finish) json_escape(&b, finish); else buf_puts(&b, "null");
4935	        buf_puts(&b, "}]}\n\n");
4936	    }
4937	    bool ok = send_all(fd, b.ptr, b.len);
4938	    buf_free(&b);
4939	    return ok;
4940	}
