4948	static void append_openai_usage_json(buf *b, const request *r,
4949	                                     int prompt_tokens, int completion_tokens) {
4950	    int cached_tokens = r ? r->cache_read_tokens : 0;
4951	    int cache_write_tokens = r ? r->cache_write_tokens : 0;
4952	    cached_tokens = clamp_usage_tokens(cached_tokens, prompt_tokens);
4953	    cache_write_tokens = clamp_usage_tokens(cache_write_tokens, prompt_tokens - cached_tokens);
4954	    /* OpenAI defines cached_tokens as prompt tokens retrieved from cache.
4955	     * Newly-prefilled tokens are useful to expose, but they are a DS4 extension
4956	     * and must stay separate so OpenAI-compatible clients do not over-count
4957	     * cache hits. */
4958	    buf_printf(b,
4959	               "{\"prompt_tokens\":%d,\"completion_tokens\":%d,\"total_tokens\":%d,"
4960	               "\"prompt_tokens_details\":{\"cached_tokens\":%d,\"cache_write_tokens\":%d}}",
4961	               prompt_tokens, completion_tokens, prompt_tokens + completion_tokens,
4962	               cached_tokens, cache_write_tokens);
4963	}
