4965	static bool sse_usage_chunk(int fd, const request *r, const char *id,
4966	                            int prompt_tokens, int completion_tokens) {
4967	    if (!r->stream_include_usage) return true;
4968	
4969	    buf b = {0};
4970	    long now = (long)time(NULL);
4971	    if (r->kind == REQ_CHAT) {
4972	        buf_printf(&b, "data: {\"id\":\"%s\",\"object\":\"chat.completion.chunk\",\"created\":%ld,\"model\":", id, now);
4973	        json_escape(&b, r->model);
4974	        buf_puts(&b, ",\"choices\":[],\"usage\":");
4975	    } else {
4976	        buf_printf(&b, "data: {\"id\":\"%s\",\"object\":\"text_completion\",\"created\":%ld,\"model\":", id, now);
4977	        json_escape(&b, r->model);
4978	        buf_puts(&b, ",\"choices\":[],\"usage\":");
