5986	static void responses_random_id(char *dst, size_t dstlen, const char *prefix) {
5987	    unsigned char bytes[12];
5988	    size_t pos = snprintf(dst, dstlen, "%s", prefix);
5989	    if (pos >= dstlen) return;
5990	    static uint64_t fallback_ctr;
5991	    if (!random_bytes(bytes, sizeof(bytes))) {
5992	        uint64_t a = ((uint64_t)time(NULL) << 32) ^ (uint64_t)getpid();
5993	        uint64_t b = ++fallback_ctr ^ (uint64_t)(uintptr_t)dst;
5994	        memcpy(bytes, &a, sizeof(a));
5995	        memcpy(bytes + sizeof(a), &b, sizeof(uint32_t));
5996	    }
5997	    static const char hex[] = "0123456789abcdef";
5998	    for (size_t i = 0; i < sizeof(bytes) && pos + 2 < dstlen; i++) {
5999	        dst[pos++] = hex[bytes[i] >> 4];
6000	        dst[pos++] = hex[bytes[i] & 15];
6001	    }
6002	    dst[pos] = '\0';
